parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "subject": {
      "type": ["string", "null"],
      "description": "Original email subject (unchanged)"
    },
    "body": {
      "type": ["string", "null"],
      "description": "Original email body (unchanged)"
    },
    "category": {
      "type": ["string", "null"],
      "enum": [
        "Billing",
        "Bug Report",
        "Account Support",
        "UI/UX Issue",
        "Logistic Issue",
        "Feature Enhancement Request",
        null
      ],
      "description": "The classified category of the email"
    },
    "priority": {
      "type": ["string", "null"],
      "enum": ["Low", "Medium", "High", null],
      "description": "The priority level of the email"
    }
  },
  "required": ["subject", "body", "category", "priority"],
  "additionalProperties": false
}
